from collections import Counter

def get_mode(data):
    if not data: return []
    counts = Counter(data)
    max_count = max(counts.values())
    return sorted(val for val, count in counts.items() if count == max_count)

if __name__ == "__main__":
    print(f"Mode: {get_mode([2, 3, 4, 3, 2, 2])}")

